// Extract grant context from webhook body
const raw = $('Narrative Request').first().json;
const body = raw.body || {};
const payload = body.$json || body;

const grant_id = payload.grantId || payload.grant_id;
const org_id = payload.org_id;

if (!grant_id || !org_id) {
  return [{
    json: {
      error: true,
      message: `Missing required fields. grant_id: ${grant_id}, org_id: ${org_id}`,
    }
  }];
}

return [{
  json: {
    grant_id,
    org_id,
    grant_title: payload.grant_title || 'Not specified',
    grant_description: payload.grant_description || 'Not specified',
    funder_name: payload.funder_name || 'Not specified',
    deadline: payload.deadline || 'Not specified',
    amount: payload.amount || 'Not specified',
  }
}];

// Filter narratives for relevance to the grant, then pair with grant context
const narratives = $('Get Narratives').all().map(item => item.json);
const gc = $('Extract Grant Context').first().json;

if (!narratives || narratives.length === 0 || !narratives[0].id) {
  return [{
    json: {
      error: true,
      message: 'No narratives found for this org',
    }
  }];
}

// Build a searchable string from grant context for relevance matching
const grantText = [
  gc.grant_title,
  gc.grant_description,
  gc.funder_name,
].join(' ').toLowerCase();

// Keywords that map narrative categories/content to grant topics
const relevanceKeywords = {
  mission: ['mission', 'organization', 'nonprofit', 'community', 'overview', 'about'],
  impact: ['impact', 'outcomes', 'results', 'data', 'metrics', 'evaluation', 'measure'],
  methods: ['methods', 'approach', 'strategy', 'program', 'activities', 'services', 'intervention'],
  evaluation: ['evaluation', 'assessment', 'measure', 'outcomes', 'data', 'metrics'],
  youth: ['youth', 'foster', 'children', 'young', 'adolescent', 'teen', 'aging out'],
  seniors: ['senior', 'aging', 'elderly', 'older adults', 'long-term care', 'alzheimer', 'dementia'],
  equity: ['equity', 'racial', 'diversity', 'inclusion', 'african american', 'disparit'],
  workforce: ['workforce', 'employment', 'job', 'career', 'professional', 'work'],
  mental_health: ['mental health', 'trauma', 'healing', 'wellness', 'behavioral'],
  community: ['community', 'volunteer', 'partner', 'collaboration', 'local'],
};

// Score each narrative for relevance
const scored = narratives.map(n => {
  const narrativeText = [
    n.title || '',
    n.category || '',
    n.content || '',
    (n.tags || []).join(' '),
  ].join(' ').toLowerCase();

  let score = 0;

  // Always include mission/overview narratives (score boost)
  if ((n.category || '').toLowerCase() === 'mission' || (n.title || '').toLowerCase().includes('mission')) {
    score += 3;
  }

  // Check if narrative category keywords appear in grant text
  for (const [category, keywords] of Object.entries(relevanceKeywords)) {
    const narrativeMatchesCategory = keywords.some(kw => narrativeText.includes(kw));
    const grantMatchesCategory = keywords.some(kw => grantText.includes(kw));
    if (narrativeMatchesCategory && grantMatchesCategory) {
      score += 2;
    }
  }

  // Direct word overlap between narrative title/category and grant text
  const titleWords = (n.title || '').toLowerCase().split(/\s+/);
  for (const word of titleWords) {
    if (word.length > 3 && grantText.includes(word)) {
      score += 1;
    }
  }

  return { narrative: n, score };
});

// Filter: keep narratives with score > 0, sorted by relevance
let relevant = scored.filter(s => s.score > 0).sort((a, b) => b.score - a.score);

// Fallback: if nothing matched, use mission + methods + impact narratives
if (relevant.length === 0) {
  const fallbackCategories = ['mission', 'methods', 'impact'];
  relevant = scored.filter(s => {
    const cat = (s.narrative.category || '').toLowerCase();
    return fallbackCategories.includes(cat);
  });
}

// Still nothing? Use all narratives
if (relevant.length === 0) {
  relevant = scored;
}

return relevant.map(s => ({
  json: {
    narrative_id: s.narrative.id,
    section_id: s.narrative.category || 'general',
    section_name: s.narrative.title,
    base_content: s.narrative.content,
    word_limit: s.narrative.metadata?.word_count || 250,
    relevance_score: s.score,
    grantContext: gc,
  }
}));

