// Format each customized narrative
const sectionInfo = $('Prepare Context').item.json;
const aiResponse = $input.first().json;

const customizedText = aiResponse.message?.content || aiResponse.text || '';

return [{
  json: {
    section_id: sectionInfo.section_id,
    section_name: sectionInfo.section_name,
    customized_content: customizedText.trim(),
    word_count: customizedText.trim().split(/\s+/).length,
    word_limit: sectionInfo.word_limit,
  }
}];

// Combine all customized narratives into final response
const allSections = $input.all();
const grantContext = $('Extract Grant Context').first().json;

const narratives = {};
for (const item of allSections) {
  const s = item.json;
  narratives[s.section_id] = {
    section_name: s.section_name,
    content: s.customized_content,
    word_count: s.word_count,
    word_limit: s.word_limit
  };
}

return [{
  json: {
    success: true,
    grant_id: grantContext.grant_id,
    funder_name: grantContext.funder_name,
    sectionsReturned: Object.keys(narratives).length,
    narratives,
    generatedAt: new Date().toISOString()
  }
}];
